using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF 9 renamed "Discriminator" to "$type". Keep old property name
            // so existing documents are still readable.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // EF 9 changed id format from "EntityName|<key>" to just "<key>".
            // Opt in to the legacy format so existing documents are found.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasIdValueGeneration(false);

            // EF 9 removed Cosmos DB indexing support (HasIndex throws).
            // Cosmos indexes are managed via the indexing policy on the container.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

